import{_ as o,o as r,c as e,a3 as d}from"./chunks/framework.BTFg6ESq.js";const p=JSON.parse('{"title":"正则批量替换","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/regex-applier.md","filePath":"user-guide/tools/regex-applier.md","lastUpdated":1778221347000}'),a={name:"user-guide/tools/regex-applier.md"};function l(n,t,s,i,c,g){return r(),e("div",null,[...t[0]||(t[0]=[d('<h1 id="正则批量替换" tabindex="-1">正则批量替换 <a class="header-anchor" href="#正则批量替换" aria-label="Permalink to &quot;正则批量替换&quot;">​</a></h1><blockquote><p>TODO: 截图 — 工具主界面（文本模式）</p></blockquote><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>正则批量替换（Regex Applier）是一个强大的文本处理工具，支持通过预设的多条正则规则链，<strong>一键批量处理文本内容或文件</strong>。无论是清洗日志、格式化代码、提取结构化数据，还是批量修改文件内容，它都能高效完成。</p><h3 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h3><ul><li><strong>双引擎设计</strong>：浏览器端 JS 引擎提供毫秒级实时预览，后端 Rust 引擎以极高性能处理大批量文件</li><li><strong>预设规则链</strong>：将多条正则规则组成&quot;预设&quot;，按顺序依次应用，支持拖拽排序和快速开关</li><li><strong>两种处理模式</strong>：直接输入文本（或粘贴剪贴板）即时处理，或选择文件/文件夹批量处理</li><li><strong>一键处理</strong>：从剪贴板读取 → 应用规则 → 写回剪贴板，一次点击完成全流程</li><li><strong>预设管理</strong>：创建、复制、导入/导出预设，内置 18 种常用正则快捷模式</li></ul><hr><h2 id="快速上手" tabindex="-1">快速上手 <a class="header-anchor" href="#快速上手" aria-label="Permalink to &quot;快速上手&quot;">​</a></h2><h3 id="场景一-文本清洗-5-分钟" tabindex="-1">场景一：文本清洗（5 分钟） <a class="header-anchor" href="#场景一-文本清洗-5-分钟" aria-label="Permalink to &quot;场景一：文本清洗（5 分钟）&quot;">​</a></h3><p>假设你有一段包含邮箱、URL 和多余空白的文本，想快速清理。</p><ol><li><p>在主页点击 <strong>正则批量替换</strong> 卡片进入工具，默认处于「文本模式」。</p><blockquote><p>TODO: 截图 — 工具默认主界面</p></blockquote></li><li><p>点击 <strong>显示预设</strong>（如已显示则跳过），然后点击 <strong>添加预设</strong> → 选择「默认预设」（或新建一个）。</p><blockquote><p>TODO: 截图 — 添加预设下拉菜单</p></blockquote></li><li><p>点击 <strong>管理规则</strong> 打开预设管理器。</p></li><li><p>在右侧编辑区输入：</p><ul><li><strong>规则名称</strong>：移除 URL</li><li><strong>正则表达式</strong>：<code>https?://[^\\s]+</code></li><li><strong>替换内容</strong>：<code>[链接已移除]</code><blockquote><p>TODO: 截图 — 规则编辑界面</p></blockquote></li></ul></li><li><p>在 <strong>测试输入</strong> 框里粘贴样例文本，右侧会实时显示替换预览。</p><blockquote><p>TODO: 截图 — 实时预览高亮效果</p></blockquote></li><li><p>点击 <strong>添加规则</strong> 继续添加：</p><ul><li><strong>规则名称</strong>：压缩空白</li><li><strong>正则</strong>：<code>\\s+</code></li><li><strong>替换</strong>：<code></code>（一个空格）</li><li><strong>多行模式</strong>：勾选 <code>g</code> 标志（JS 引擎会默认添加 <code>g</code> 和 <code>m</code> 标志）</li></ul></li><li><p>回到主界面，在 <strong>输入文本</strong> 框粘贴待处理内容，<strong>输出文本</strong> 面板会<strong>自动</strong>显示处理结果。</p><blockquote><p>TODO: 截图 — 输入/输出对比</p></blockquote></li><li><p>点击 <strong>复制</strong> 或 <strong>发送到聊天</strong> 使用处理结果。</p></li></ol><h3 id="场景二-批量处理文件" tabindex="-1">场景二：批量处理文件 <a class="header-anchor" href="#场景二-批量处理文件" aria-label="Permalink to &quot;场景二：批量处理文件&quot;">​</a></h3><ol><li><p>将顶部的 <strong>处理模式</strong> 切换为「文件模式」。</p><blockquote><p>TODO: 截图 — 模式切换按钮</p></blockquote></li><li><p>通过拖拽或点击按钮，添加要处理的文件/文件夹。</p><blockquote><p>TODO: 截图 — 文件模式界面，带拖拽高亮</p></blockquote></li><li><p>设置 <strong>输出目录</strong>（处理后的文件将保存在此）。</p></li><li><p>可选：添加 <strong>文件名后缀</strong>（如 <code>_processed</code>），避免覆盖原文件。</p></li><li><p>点击 <strong>开始处理文件</strong>，工具将调用 Rust 后端引擎执行批量替换。</p><blockquote><p>TODO: 截图 — 处理中/完成状态</p></blockquote></li></ol><hr><h2 id="功能详解" tabindex="-1">功能详解 <a class="header-anchor" href="#功能详解" aria-label="Permalink to &quot;功能详解&quot;">​</a></h2><h3 id="_1-顶部操作栏" tabindex="-1">① 顶部操作栏 <a class="header-anchor" href="#_1-顶部操作栏" aria-label="Permalink to &quot;① 顶部操作栏&quot;">​</a></h3><table tabindex="0"><thead><tr><th>区域</th><th>说明</th></tr></thead><tbody><tr><td><strong>处理模式</strong></td><td>「文本模式」用于即时处理输入内容；「文件模式」用于处理磁盘上的文件</td></tr><tr><td><strong>显示/隐藏预设</strong></td><td>切换预设选择区域的可见性</td></tr><tr><td><strong>查看日志</strong></td><td>打开日志弹窗，显示规则应用记录和错误信息（有错误时会显示徽章）</td></tr><tr><td><strong>管理规则</strong></td><td>打开预设管理器弹窗，进行规则的增删改查和测试</td></tr></tbody></table><h3 id="_2-预设系统" tabindex="-1">② 预设系统 <a class="header-anchor" href="#_2-预设系统" aria-label="Permalink to &quot;② 预设系统&quot;">​</a></h3><p>预设是一组正则规则的集合，按<strong>顺序</strong>依次应用。支持：</p><ul><li><strong>添加预设</strong>：从已有预设列表中选择，预设按添加顺序排列</li><li><strong>拖拽排序</strong>：通过拖拽预设标签调整应用顺序 <blockquote><p>TODO: 截图 — 预设标签拖拽排序</p></blockquote></li><li><strong>移除预设</strong>：点击预设标签上的 ✕ 按钮</li><li><strong>状态持久化</strong>：选中的预设和排序会在重新打开工具后自动恢复</li></ul><h3 id="_3-文本模式" tabindex="-1">③ 文本模式 <a class="header-anchor" href="#_3-文本模式" aria-label="Permalink to &quot;③ 文本模式&quot;">​</a></h3><ul><li><strong>输入文本</strong>：支持直接输入、粘贴（<code>Ctrl+V</code>）或从剪贴板读取</li><li><strong>一键处理</strong>：点击「一键处理」按钮，自动从剪贴板读取 → 应用规则 → 写回剪贴板</li><li><strong>输出文本</strong>：只读文本框，输入变化或预设变化时<strong>自动实时更新</strong></li><li><strong>发送到聊天</strong>：将处理结果直接发送到 LLM 聊天输入框</li></ul><h3 id="_4-文件模式" tabindex="-1">④ 文件模式 <a class="header-anchor" href="#_4-文件模式" aria-label="Permalink to &quot;④ 文件模式&quot;">​</a></h3><table tabindex="0"><thead><tr><th>参数</th><th>说明</th></tr></thead><tbody><tr><td><strong>待处理文件</strong></td><td>支持拖拽或 <code>选择文件</code>/<code>选择文件夹</code> 添加；每个文件显示处理状态（待处理/处理中/成功/失败）</td></tr><tr><td><strong>输出目录</strong></td><td>处理后的文件保存目录，支持拖拽设置</td></tr><tr><td><strong>文件名后缀</strong></td><td>在原文件名后添加后缀（如 <code>log_clean</code> → <code>log_clean.txt</code>）</td></tr><tr><td><strong>强制 .txt</strong></td><td>忽略原始扩展名，统一保存为 <code>.txt</code> 格式</td></tr><tr><td><strong>处理后清除</strong></td><td>处理成功的文件自动从列表移除</td></tr></tbody></table><h3 id="_5-预设管理器-管理规则弹窗" tabindex="-1">⑤ 预设管理器（管理规则弹窗） <a class="header-anchor" href="#_5-预设管理器-管理规则弹窗" aria-label="Permalink to &quot;⑤ 预设管理器（管理规则弹窗）&quot;">​</a></h3><blockquote><p>TODO: 截图 — 预设管理器全貌</p></blockquote><p><strong>左侧面板 — 预设与规则列表：</strong></p><table tabindex="0"><thead><tr><th>操作</th><th>说明</th></tr></thead><tbody><tr><td><strong>预设选择器</strong></td><td>下拉切换当前编辑的预设</td></tr><tr><td><strong>新建 / 复制 / 重命名 / 删除</strong></td><td>预设的完整生命周期管理（至少保留一个预设）</td></tr><tr><td><strong>从文件导入</strong></td><td>选择 <code>.json</code> 文件导入预设</td></tr><tr><td><strong>从剪贴板导入</strong></td><td>粘贴 JSON 格式的预设或规则数组</td></tr><tr><td><strong>导出预设</strong></td><td>将当前预设保存为 <code>.json</code> 文件</td></tr><tr><td><strong>规则列表</strong></td><td>显示预设中的所有规则；支持拖拽排序、关键词搜索、启用/禁用开关、快速删除</td></tr><tr><td><strong>添加规则</strong></td><td>为当前预设新增一条空规则</td></tr></tbody></table><p><strong>右侧面板 — 规则编辑与测试：</strong></p><table tabindex="0"><thead><tr><th>区域</th><th>说明</th></tr></thead><tbody><tr><td><strong>规则名称</strong></td><td>可选，便于识别规则用途</td></tr><tr><td><strong>正则表达式</strong></td><td>支持 <code>/pattern/flags</code> 语法教程；验证失败时显示具体错误</td></tr><tr><td><strong>Rust 兼容性</strong></td><td>实时检测正则是否能在 Rust 后端执行（影响文件模式）</td></tr><tr><td><strong>快捷规则</strong></td><td>18 种常用模式，点击直接插入到正则输入框的光标位置</td></tr><tr><td><strong>替换内容</strong></td><td>支持捕获组引用 <code>$1</code>、<code>$2</code> 等</td></tr><tr><td><strong>测试输入</strong></td><td>输入样例文本，实时查看匹配次数和替换结果，匹配项高亮显示</td></tr><tr><td><strong>输出预览</strong></td><td>显示替换后的文本，替换内容以绿色高亮</td></tr></tbody></table><blockquote><p>TODO: 截图 — 规则测试区，展示匹配高亮</p></blockquote><hr><h2 id="高级用法" tabindex="-1">高级用法 <a class="header-anchor" href="#高级用法" aria-label="Permalink to &quot;高级用法&quot;">​</a></h2><h3 id="组合场景-清洗-格式化一条龙" tabindex="-1">组合场景：清洗+格式化一条龙 <a class="header-anchor" href="#组合场景-清洗-格式化一条龙" aria-label="Permalink to &quot;组合场景：清洗+格式化一条龙&quot;">​</a></h3><p>创建一个预设，包含以下规则链：</p><ol><li><code>^[ \\t]+</code> → <code>&quot;&quot;</code>（移除行首空白）</li><li><code>\\s+$</code> → <code>&quot;&quot;</code>（移除行尾空白）</li><li><code>\\r\\n</code> → <code>\\n</code>（统一换行符）</li><li><code>\\n{3,}</code> → <code>\\n\\n</code>（压缩多余空行）</li></ol><p>这样一条规则链就变成了一个「文本清洗工坊」，每次只需选择预设 → 粘贴 → 一键处理。</p><h3 id="批量替换实战" tabindex="-1">批量替换实战 <a class="header-anchor" href="#批量替换实战" aria-label="Permalink to &quot;批量替换实战&quot;">​</a></h3><p>假设你要批量处理 <code>src/</code> 下的所有 Markdown 文件：</p><ol><li>创建预设：「替换内部链接」 <ul><li>规则：<code>\\]\\(\\.\\.\\/</code> → <code>](</code>（将相对路径 <code>../</code> 替换为当前目录）</li></ul></li><li>切换到文件模式，添加 <code>src/</code> 文件夹</li><li>设置输出目录为 <code>src_clean/</code></li><li>设置后缀 <code>_cleaned</code></li><li>点击处理</li></ol><p>Rust 引擎会在几秒内处理所有文件，并在日志中显示每项操作详情。</p><h3 id="正则语法提示" tabindex="-1">正则语法提示 <a class="header-anchor" href="#正则语法提示" aria-label="Permalink to &quot;正则语法提示&quot;">​</a></h3><p>工具支持<strong>标准 JavaScript 正则语法</strong>（<code>/pattern/flags</code> 格式）：</p><table tabindex="0"><thead><tr><th>标志</th><th>含义</th></tr></thead><tbody><tr><td><code>g</code></td><td>全局匹配（默认启用）</td></tr><tr><td><code>m</code></td><td>多行模式（默认启用）</td></tr><tr><td><code>i</code></td><td>忽略大小写</td></tr><tr><td><code>s</code></td><td>点号匹配换行符</td></tr></tbody></table><p><strong>常用捕获组引用</strong>：</p><ul><li><code>$1</code>, <code>$2</code> — 按顺序引用捕获组</li><li><code>$&amp;</code> — 匹配的完整文本</li><li>`$`` — 匹配前的文本</li><li><code>$&#39;</code> — 匹配后的文本</li></ul><hr><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q-为什么我的规则在文本模式有效-文件模式却失效了" tabindex="-1">Q：为什么我的规则在文本模式有效，文件模式却失效了？ <a class="header-anchor" href="#q-为什么我的规则在文本模式有效-文件模式却失效了" aria-label="Permalink to &quot;Q：为什么我的规则在文本模式有效，文件模式却失效了？&quot;">​</a></h3><p><strong>A</strong>：可能是正则语法在 Rust 后端不兼容。JS 和 Rust 的正则引擎有差异（如 Rust 不支持前瞻 <code>(?=...)</code> 和后瞻 <code>(?&lt;=...)</code>）。在管理规则时，右侧会显示 <strong>Rust 兼容性</strong> 状态标签，如果标记为「不兼容」，文件模式将跳过该规则。建议在文件模式中避免使用前瞻/后瞻断言。</p><h3 id="q-文件处理到一半中断了-已经修改的文件会怎样" tabindex="-1">Q：文件处理到一半中断了，已经修改的文件会怎样？ <a class="header-anchor" href="#q-文件处理到一半中断了-已经修改的文件会怎样" aria-label="Permalink to &quot;Q：文件处理到一半中断了，已经修改的文件会怎样？&quot;">​</a></h3><p><strong>A</strong>：Rust 引擎采用顺序处理（逐文件读取 → 应用规则 → 写入），处理成功的文件会完整写入输出目录。中断时，已成功处理的文件不受影响，未处理或处理中的文件需要重新执行。</p><h3 id="q-如何分享我的预设给其他人" tabindex="-1">Q：如何分享我的预设给其他人？ <a class="header-anchor" href="#q-如何分享我的预设给其他人" aria-label="Permalink to &quot;Q：如何分享我的预设给其他人？&quot;">​</a></h3><p><strong>A</strong>：在预设管理器中打开预设，点击 <strong>导出预设</strong> 保存为 <code>.json</code> 文件。接收者在同一页面点击 <strong>从文件导入</strong> 或 <strong>从剪贴板导入</strong> 即可使用。</p><h3 id="q-一键处理-粘贴-→-处理-→-复制-为什么没有弹出提示" tabindex="-1">Q：一键处理（粘贴 → 处理 → 复制）为什么没有弹出提示？ <a class="header-anchor" href="#q-一键处理-粘贴-→-处理-→-复制-为什么没有弹出提示" aria-label="Permalink to &quot;Q：一键处理（粘贴 → 处理 → 复制）为什么没有弹出提示？&quot;">​</a></h3><p><strong>A</strong>：一键处理会直接操作系统剪贴板，处理完成后会弹出成功提示。如果没有任何反应，请检查：</p><ol><li>是否已选中至少一个预设</li><li>剪贴板中是否有文本内容</li><li>查看日志面板是否有错误信息</li></ol><h3 id="q-我可以对同一个预设中的规则调整执行顺序吗" tabindex="-1">Q：我可以对同一个预设中的规则调整执行顺序吗？ <a class="header-anchor" href="#q-我可以对同一个预设中的规则调整执行顺序吗" aria-label="Permalink to &quot;Q：我可以对同一个预设中的规则调整执行顺序吗？&quot;">​</a></h3><p><strong>A</strong>：可以。在预设管理器的左侧规则列表中，直接<strong>拖拽</strong>规则卡片即可调整顺序。规则从上到下依次执行，前面的输出会作为后面的输入。</p>',59)])])}const u=o(a,[["render",l]]);export{p as __pageData,u as default};
